import React from 'react';
import { FiTarget, FiArrowRight } from 'react-icons/fi';
import { generateDynamicData } from '../../utils/dynamicData';

interface Props { skillId?: string; }

const SkillRecommendations: React.FC<Props> = ({ skillId }) => {
  const data = generateDynamicData(skillId);

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-200">
        <h3 className="text-2xl font-bold text-gray-900 mb-6 flex items-center gap-2">
          <FiTarget className="text-indigo-500" /> Priority Recommendations for {data.skill}
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {data.recommendations.map((rec, i) => (
            <div key={i} className="p-5 border border-indigo-100 bg-indigo-50/50 rounded-xl hover:shadow-md transition-shadow">
              <div className="flex justify-between items-start mb-3">
                <span className="px-2 py-1 bg-indigo-100 text-indigo-700 text-xs font-bold rounded-md uppercase">
                  {rec.priority} Priority
                </span>
                <span className="text-indigo-400 text-sm font-medium">{rec.time}</span>
              </div>
              <h4 className="font-bold text-gray-900 mb-2">{rec.title}</h4>
              <button className="text-indigo-600 font-semibold text-sm flex items-center gap-1 hover:gap-2 transition-all">
                Start Learning <FiArrowRight />
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default SkillRecommendations;
